package main

import (
	"crypto/aes"
	"crypto/cipher"
	"fmt"
)

func ctr(key, nonce, input []byte) []byte {
	block, err := aes.NewCipher(key)
	if err != nil { panic(err) }
	output := make([]byte, len(input))
	cipher.NewCTR(block, nonce).XORKeyStream(output, input)
	return output
}

func main() {
	key, nonce := make([]byte, 16), make([]byte, 16)
	key[0], nonce[15] = 2, 1
	left, right := ctr(key, nonce, []byte("PAY-ALICE-1000")), ctr(key, nonce, []byte("PAY-BOB---900"))
	fmt.Printf("same_nonce=%t relation_leaked=%t authenticated=false production=false\n", true, left[0]^right[0] == 'P'^'P')
}
